const body = $json.body || $json;
const app = {
  brand_name: body.brand_name || body.brand || '',
  product_name: body.product_name || body.product || '',
  category: body.category || 'Uncategorized',
  website: body.website || body.url || '',
  retail_price: body.retail_price || '',
  wholesale_price: body.wholesale_price || '',
  commission_offer: body.commission_offer || body.commission || '',
  contact_email: body.email || body.contact_email || '',
  fit_reason: body.fit_reason || body.message || '',
  status: 'New',
  suggested_package: 'Octo Launch Pack - 199 EUR',
  created_at: new Date().toISOString()
};
let score = 0;
if (app.website) score += 20;
if (app.contact_email) score += 20;
if (app.commission_offer) score += 20;
if (app.retail_price) score += 10;
if (app.fit_reason.length > 30) score += 20;
if (/ai|smart|wearable|gadget|tool|robot|home/i.test(app.product_name + ' ' + app.category)) score += 10;
app.qualification_score = Math.min(score, 100);
app.priority = score >= 70 ? 'High' : score >= 40 ? 'Medium' : 'Low';
return [{ json: app }];
